import { IMessageComposer } from '@nitrots/nitro-renderer';

export class ToggleGangChatComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(enabled: boolean) {
        this._data = [enabled];
        console.log(
            `Packet ToggleGangChatComposer sent. Gang chat enabled: ${enabled}`
        );
    }

    public getMessageArray(): any[] {
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
